import './App.css';
import React from 'react';

import {BrowserRouter, Route, Routes} from "react-router-dom"
import  { useReducer, useRef, useEffect} from 'react';
import { useState } from 'react';



// pages 
import Review from './pages/Review'
import Like from './pages/Like'
import MyPage from './pages/MyPage';
import Home from './pages/Home';
import Auth from "./pages/Auth";

export const DiaryStateContext = React.createContext();

export const DiraryDispatchContext = React.createContext();

const dummyData = [
  {
    id : 1,
    name : 'Julia',
    level : 'best'

  }

]

function App() {

  // const [ < 상태 객체 >, < dispatch 함수 > ]



  return (
    <DiaryStateContext.Provider value={dummyData}>
      <DiraryDispatchContext.Provider>

        <BrowserRouter>
          <div className = "App">

            <Routes>
              <Route path ="/" element = {<Home/>} />
              <Route path="/oauth/kakao/callback" element={<Authcheck />} />
              <Route path="/login" element={<KakaoLogin />} />
              <Route path="/review" element = {<Review/>} />
              <Route path="/like" element = {<Like/>} />
              <Route path='/mypage' element = {<MyPage/>} />

            </Routes>
          </div>

        </BrowserRouter>
      </DiraryDispatchContext.Provider>
      </DiaryStateContext.Provider>

  );
}

export default App;

function KakaoLogin() {
  const REST_API_KEY = "32bb1444ddc8c71c3924daaef84ae5e6";
  const REDIRECT_URI = "http://localhost:3007/oauth/kakao/callback";
  const KAKAO_AUTH_URL = `https://kauth.kakao.com/oauth/authorize?client_id=${REST_API_KEY}&redirect_uri=${REDIRECT_URI}&response_type=code`;
  return (
  <a href={KAKAO_AUTH_URL}>Kakao Login</a>
  );
}

function Authcheck() {
  return Auth()
}
